var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"결국, 다시 돌아오셨군요.","JPN":"結局、お戻りになりましたね。","ENG":"So, you've come back after all.","TWN":"結果，你又回來了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_6"},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"만남과 이별 모두, 제 의지와는 상관없이 멋대로 정하셨잖습니까.","JPN":"出会いも別れも、私の意志とは関係なく勝手に決めていたではないですか。","ENG":"You chose when to meet and part, regardless of my will.","TWN":"無論是相遇還是離別，你都隨意決定了，不顧我的意願。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_21"},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는 못다한 이야기를 하러 왔을 뿐입니다, 그레이스 경.","JPN":"私は、果たせなかった話をしに来ただけです、グレース卿。","ENG":"I came only to finish what was left unsaid, Dame Grace.","TWN":"我只是來講述未完的故事，葛瑞絲小姐。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_22"},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그레이스 경이라… 이상한 말씀을 하시네요.","JPN":"グレース卿……変なことをおっしゃいますね。","ENG":"\\"Dame Grace\\"... Now that's strange to hear.","TWN":"葛瑞絲小姐嗎……說的話真奇怪呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_7"},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 모든 것은 클리파 에너지가 생전의 모습을 본따 만든 허깨비에 불과합니다.","JPN":"私のすべてはクリファエネルギーが生前の姿を真似て作った偽物です。","ENG":"What you see is just a hollow shell, a phantom shaped by Qlipha energy.","TWN":"我的一切不過是逆卡巴拉能量模仿生前樣貌製造的幻影罷了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_8"},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"귀공께서 보는 것은 그저 악몽에 불과한 것이지요.","JPN":"貴殿が見ているのは、ただの悪夢に過ぎません。","ENG":"What stands before you is only a nightmare.","TWN":"你所看到的不過是惡夢罷了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_9"},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……생각해보면 단순한 이야기였습니다.","JPN":"……考えてみれば、単純な話でした。","ENG":"...Looking back, it was a simple story.","TWN":"……仔細想想，這只是個簡單的故事。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_23"},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"경께서 말씀하신 악몽의 계기는 늘상 같았고, 그 악몽이 보여주는 것 또한 동일했죠.","JPN":"卿がおっしゃっていた悪夢のきっかけはいつも同じで、その悪夢が見せてくれることもまた同じでした。","ENG":"The nightmare you spoke of always began the same way and showed the same things.","TWN":"你所說的惡夢的起因總是相同，而惡夢所展示的內容也一樣。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_24"},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"처음 당신을 만난 계기도 어렴풋이 남아있던 힘을 깨우친 순간이었습니다.","JPN":"初めてあなたと出会ったきっかけも、微かに残っていた力に気づいた瞬間でした。","ENG":"Even the first time we met, it was the moment I awakened that faint trace of power.","TWN":"第一次遇見你，也是我隱約喚醒力量的時刻。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_25"},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신은 악몽 따위가 아니에요.","JPN":"あなたは悪夢なんかではありません。","ENG":"You're no nightmare.","TWN":"你不是惡夢之類的東西。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_26"},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금껏 제 자신을 몇 번이나 지켜 준… 별의 가호.","JPN":"今まで私自身を何度も守ってくれた……星の加護。","ENG":"You've protected me countless times... You're the Blessing of the Stars.","TWN":"至今為止多次守護我的……星星的守護。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_27"},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 안에 담겨있던, 제가 되찾고자 한 정의입니다.","JPN":"その中に込められていた、私が取り戻そうとしていた正義です。","ENG":"And within that, the justice I've sought to reclaim.","TWN":"那裡面包含著我想要找回的正義。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_28"},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……정의라.","JPN":"……正義ですか。","ENG":"...Justice, is it?","TWN":"……正義嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_10"},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세계를 멸망시키려 한 마왕의 동료에게는 어울리지 않는 말이군요.","JPN":"世界を滅亡させようとしていた魔王の仲間には相応しくない言葉ですね。","ENG":"Hardly fitting for someone who once sided with a Demon Lord bent on destruction.","TWN":"這話可不適合想要毀滅世界的魔王的同夥呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_11"},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예. 어울리지 않습니다.","JPN":"はい。相応しくありません。","ENG":"That's right. It isn't fitting.","TWN":"是的，不合適。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_29"},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그러니 도망치지 마세요, 그레이스 경.","JPN":"だから逃げないでください、グレース卿。","ENG":"That's why you mustn't run, Dame Grace.","TWN":"所以不要逃跑，葛瑞絲小姐。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_30"},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"도망치는 것이 아닌, 제 나름대로의 속죄입니다.","JPN":"逃げているのではなく、私なりの贖罪なのです。","ENG":"I'm not running. This is my form of atonement.","TWN":"這不是逃避，而是我自己的贖罪方式。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_12"},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"기연으로 사도가 되는 것은 피했으나 제 근원은 네헤모트와 동일한 세계에서 비롯된 것.","JPN":"奇縁のおかげで使徒になることは避けられたのですが、私の根源はネヘモトと同じ世界から来たもの。","ENG":"Though I avoided becoming an Apostle, my origins lie in the same world as Nehemoth.","TWN":"雖然因機緣避免成為使徒，但我的根源來自與貝赫莫特相同的世界。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_13"},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"카란티시르는 그것을 알고 있음에 무구에 담긴 클리파로 별빛을 침식시키려는 것이겠으나…….","JPN":"カランティシルはそれを知っているので、武具に宿っているクリファで星の光を侵食させようとしているのでしょうが……","ENG":"Carantisir knows this. That's why he's trying to corrupt the starlight with Qlipha from the Armament...","TWN":"卡蘭堤西爾知道這一點，想用武具中的逆卡巴拉侵蝕星光……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_14"},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 스스로 별을 붕괴시킨다면 그 또한 무의미해지겠죠.","JPN":"私自ら星を崩壊させるなら、それもまた無意味になるはず。","ENG":"But if I destroy the star myself, all of that becomes meaningless.","TWN":"如果我自己摧毀了星星，那也將變得毫無意義吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_15"},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……그게, 당신이 바라는 최후입니까?","JPN":"……それが、あなたの望む最後ですか？","ENG":"...Is that really how you want it to end?","TWN":"……那就是你所期望的結局嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_31"},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"많은 사람들은 인도자의 무구를 떠받치며 그들의 전승을 신화처럼 여기지만.","JPN":"多くの人は導き手の武具を崇め、彼らの伝承を神話のように思っているのですが。","ENG":"Many revere the Star Guide's Armament and consider the legend as myth.","TWN":"許多人將引導者的無垢視為神話般的傳說，崇拜著他們的勝利。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_16"},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"실상 별의 무구에 담긴 별빛은 인도자의 운명을 빚어낸 것에 불과합니다.","JPN":"実際星の武具に込められている星の光は、導き手の運命を打ち鍛えたものに過ぎません。","ENG":"But the starlight within only exists to shape the Guide's fate.","TWN":"實際上，星之武具中的星光不過是塑造了引導者的命運。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_17"},{"id":"L38_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"죽기 직전 가장 밝게 빛나는 별빛을 위해 제 한 몸을 희생하는 것이지요.","JPN":"死ぬ前に最も輝かしく光る星の光のために、自身を犠牲にするのです。","ENG":"In the end, it sacrifices itself to shine brightest before dying.","TWN":"為了在臨死前綻放最耀眼的星光而獻身。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_18"},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"방식이 달라졌을 뿐, 제 운명은 처음부터 정해져 있었습니다.","JPN":"方法が異なっているだけで、私の運命は最初から決まっていました。","ENG":"My fate was set from the start. Only the method has changed.","TWN":"只是方式改變了，我的命運從一開始就已經註定了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_19"},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"멸망한 옛 고향에 미련이 남아 애써 그것을 붙잡고 있었으나…….","JPN":"滅亡した昔の故郷に未練を感じ、頑張ってそれを引き止めてはいたのですが……","ENG":"I clung to my ruined homeland out of regret...","TWN":"對已毀滅的故鄉仍有留戀，努力想要抓住它……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_20"},{"id":"L43_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"결국 모든 것이 제자리로 돌아갈 뿐입니다.","JPN":"結局、すべてはあるべき場所に戻るだけです。","ENG":"But in the end, everything returns to where it began.","TWN":"但最終所有東西都回歸原位。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_21"},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"더 이상 여러분의 정의를 추구하는데 별의 인도를 따를 필요는 없어요.","JPN":"もう皆さんの正義を追求するのに、星の導きに従う必要はありません。","ENG":"There's no need to follow the star's guidance to seek justice.","TWN":"不再需要依靠星之引導來追求你們的正義了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_22"},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"패배자의 길을 답습하기만 해서야 경께서 원하시는 기사는 될 수 없을 겁니다.","JPN":"敗北者の道をたどることだけでは、卿がお望みの騎士にはなれないはずですもの。","ENG":"So long as you only repeat a loser's path, you'll never become the knight you wish to be.","TWN":"如果只是重複失敗者的道路，是無法成為你所期望的騎士的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_23"},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……모든 여정은 거창한 목표가 아닌 사사로운 마음에서 비롯된다.","JPN":"……すべての旅路は大層な目標ではなく、個人的な心情から始まる。","ENG":"...Every journey begins not with some grand purpose, but with a simple desire.","TWN":"……所有的旅程都始於微小的心願，而非宏偉的目標。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_32"},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경께 그 말을 들은 직후 줄곧 생각했습니다.","JPN":"グレース卿にそれを言われてから、ずっと考えていました。","ENG":"I kept thinking about that after hearing it from you, Dame Grace.","TWN":"聽到葛瑞絲小姐的話後，我一直在思考。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_33"},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"기사단의 정의에 의문을 품은 제가 쫓고 있던 것이 과연 무엇이었는지.","JPN":"騎士団の正義に疑問を抱いた私が追っていたのは、いったい何だったのか。","ENG":"After doubting the justice of the Order, I started questioning what I'd really been chasing after.","TWN":"對騎士團的正義產生疑問的我，究竟在追尋什麼。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_34"},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제가… 무엇 때문에 기사가 되고 싶었는지.","JPN":"私は……何のために騎士になりたかったのか。","ENG":"Why I... wanted to be a knight in the first place.","TWN":"我……為什麼想成為騎士。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_35"},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어린 시절, 별 하나 없는 검은 하늘에 손을 뻗은 적이 있습니다.","JPN":"小さい頃、星一つない黒い空に手を伸ばしてみたことがあります。","ENG":"As a child, I once reached out to a starless sky.","TWN":"小時候，我曾伸手觸摸無星的黑色天空。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_36"},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"뭘 잡고 싶었는지 이제는 기억조차 나지 않지만…… 그 손을, 옆에 있던 오빠가 잡아 주더군요.","JPN":"何が掴みたかったのか、今となっては覚えていませんが……その手を、隣にいた兄が握ってくれたのです。","ENG":"I can't even remember what I was trying to grab... but my brother took my hand.","TWN":"雖然已經不記得想抓住什麼了……但哥哥抓住了我的手。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_37"},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는, 그런 기사가 되고 싶었어요.","JPN":"私は、そういう騎士になりたかった。","ENG":"That's the kind of knight I wanted to become.","TWN":"我想成為那樣的騎士。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_38"},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"꿈은 이룬 것 같나요?","JPN":"夢は叶いましたか？","ENG":"And? Do you think you've realized that dream?","TWN":"夢想實現了嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_24"},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"조금은 가까워졌나 싶었는데… 아니더군요. 아직 노력해야 할 것 같습니다.","JPN":"少しは叶ったかと思っていたのですが……違いました。まだまだ頑張らないといけませんね。","ENG":"I thought I was close... but no. I still have a long way to go.","TWN":"以為稍微拉近了一些距離……但並不是呢。看來還需要努力。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_39"},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다행이네요. 변치 않은 꿈이 그대를 지탱해주고 있으니.","JPN":"良かったですね。変わらない夢が貴方を支えてくれているのですから。","ENG":"I'm glad. It means your dream hasn't changed. It still guides you.","TWN":"真是幸運。未曾改變的夢想支撐著你。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_25"},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예. 수많은 별들이 지금도 제 곁을 지켜주고 있습니다.","JPN":"はい。数多くの星々が、今も私のそばで守ってくれています。","ENG":"Yes. Countless stars still watch over me.","TWN":"是的。無數的星星現在也在守護著我。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_40"},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저 역시 그들의 별이 될 수 있다고 말해주면서요.","JPN":"私もまた、彼らの星になれると言ってくれながら。","ENG":"And I believe I can become a star for others too.","TWN":"我也告訴他們，我可以成為他們的星星。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_41"},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"전부 그레이스 경께서 남겨 주신… 기사단이 제게 안겨준 소중한 추억입니다.","JPN":"全部、グレース卿が残してくれた……騎士団が私に与えてくれた大切な思い出です。","ENG":"Those are the memories you left me... The Order gave me that gift.","TWN":"全部都是葛瑞絲小姐留下的……騎士團給予我的珍貴回憶。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_42"},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"별의 인도가 거짓일지 언정, 당신이라는 별은 모두를 이끌었어요.","JPN":"星の導きが嘘であるとしても、あなたという星はみんなを導いてくれました。","ENG":"Even if the guidance of the stars was false, your light led us all.","TWN":"即便星之引導者是虛假的，你這顆星星也引領了所有人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_43"},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"빛나지 않는 별이라 한들 한순간의 이정표로 삼을 수는 있겠지요.","JPN":"光らない星だとしても、一瞬の道しるべと思うことはできます。","ENG":"Even a dim star can be a guide, if only for a moment.","TWN":"即使是不閃耀的星星，也可以成為瞬間的路標吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_26"},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"하지만 그것에 눈이 팔려 희망을 쫓아서는 더욱 고통스러운 최후를 맞이할 뿐입니다.","JPN":"ですがそれに惹かれて希望を追っては、もっと苦しい最後を迎えるだけです。","ENG":"But chasing that light only brings a more painful end.","TWN":"但是如果被它迷惑而追逐希望，只會迎來更加痛苦的結局。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_27"},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세상에 온전한 구원은 없고, 저희가 걸어 나간 길의 끝은 낭떠러지니까요.","JPN":"世界に完全な救いはなく、私たちが歩いてきた道の果てには崖があるのですから。","ENG":"There is no true salvation. Only cliffs await at the end of our path.","TWN":"這個世界沒有完美的救贖，我們走過的路盡頭是懸崖。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_28"},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 길을 따라간 여러분의 최후는 고통스러우셨습니까?","JPN":"その道を歩いた皆さんの最後は苦しかったのですか？","ENG":"Was your ending truly so painful?","TWN":"沿著那條路走的你們，最後是否痛苦不堪？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_44"},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 차디찬 고독이, 못다 건넨 말이 첨예되어 미련으로 남아있지요.","JPN":"はい。冷たい孤独が、伝えられなかった言葉が、研ぎ澄まされては未練として残っています。","ENG":"Yes. Bitter loneliness. And unsaid words sharpened into regret.","TWN":"是的。冰冷的孤獨，未曾說出口的話語化作尖銳的執念，仍然留存於心。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_29"},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"고통스러운 최후일지 언정, 그곳에 다다르기 전 그 길을 걸어갔음을.","JPN":"苦しい最後であっても、そこにたどり着くまでの道を歩んだことを。","ENG":"Even if the end was painful, after reaching the end of the path...","TWN":"即便是痛苦的終結，也要在抵達之前走過那條路。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_45"},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"후회하십니까?","JPN":"後悔していますか？","ENG":"Do you regret it?","TWN":"你後悔嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_46"},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"필사의 각오만으로는 거스를 수 없는 것이 세상의 섭리입니다.","JPN":"必死の覚悟だけでは逆らえないものが世界の摂理というものです。","ENG":"Determination alone cannot defy the laws of the world.","TWN":"僅憑拼死的決心是無法逆轉世界的法則的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_30"},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"알고 있습니다. 알렌 경께서도 비슷한 말씀을 하셨거든요.","JPN":"わかっています。アレン卿も同じようなことを言っていたので。","ENG":"I know. Sir Allen once said something similar.","TWN":"我知道。艾倫卿也說過類似的話。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_47"},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그분께서는 이런 현실을 바꾸려 하지 말고, 기사이길 포기하라 말씀하셨지만…….","JPN":"あの方はこんな現実を変えようとせず、騎士であることを諦めろとおっしゃいましたが……","ENG":"He told me not to try changing reality. To stop being a knight...","TWN":"他告訴我不要試圖改變這種現實，而是放棄成為騎士……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_48"},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"틀려요. 전 무언가로부터 현실을 바꾸고 싶은 게 아닙니다.","JPN":"違います。私は何かから現実を変えたいわけではありません。","ENG":"But he was wrong. I'm not trying to change reality itself.","TWN":"錯了。我並不是想通過什麼來改變現實。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_49"},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는 그저-.","JPN":"私はただ……","ENG":"I just–","TWN":"我只是-"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_50"},{"id":"L33_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……무리하지 말게, 그레이스.","JPN":"……無理するな、グレース。","ENG":"...Don't push yourself too hard, Grace.","TWN":"……別勉強自己，葛瑞絲。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"연속된 패전은 그대의 잘못이 아니야.","JPN":"立てつづけの敗戦は君のせいではない。","ENG":"The recent losses weren't your fault.","TWN":"連續的敗戰不是你的錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"잘못은 없더라도 책임은 있는 법이지요.","JPN":"私のせいでなくても、責任はあります。","ENG":"Even if they weren't, I'm still responsible.","TWN":"即使沒有過錯，也要承擔責任。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 책임감이 자네를 짓누르는 게 느껴져서 하는 말이야.","JPN":"その責任感に君が押しつぶされそうだから言っているんだ。","ENG":"That sense of responsibility is crushing you.","TWN":"我說這些是因為我感覺到那份責任感正在壓垮你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"스스로를 희생하면서까지 모든 걸 짊어질 필요는…….","JPN":"自分を犠牲にしてまですべてを背負う必要は……","ENG":"You don't have to sacrifice yourself by carrying everything by yourself...","TWN":"沒有必要為了犧牲自己而承擔一切……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"희생이라니. 섭섭한 말씀을 하시네요.","JPN":"犠牲だなんて、寂しいことをおっしゃるのね。","ENG":"\\"Sacrifice\\"? That's a bit harsh.","TWN":"犧牲什麼的，你這就讓人傷心了呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_31"},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는…… 이 세계가 좋아요, 알렌.","JPN":"私は……この世界が好きなのです、アレン。","ENG":"I just... I love this world, Allen.","TWN":"艾倫，我喜歡這個世界。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_32"},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세상이 어둠에 잠겼을지언정 서로가 서로를 의지하고.","JPN":"世界が闇に呑まれるとしても、お互いを頼り。","ENG":"Even in darkness, people still reach for each other.","TWN":"即使世界陷入黑暗，我們也要互相依靠。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_33"},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부족하게나마 내일을 맞이하기 위해 희망이라는 단어를 비추려 노력하는.","JPN":"微力ながらも、明日を迎えるために希望を照らそうと努力する。","ENG":"They try, however clumsily, to greet tomorrow with hope.","TWN":"儘管微不足道，但仍努力讓希望之光照亮明天。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_34"},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그리고… 소중한 사람들이 곁에 있어주는 이곳이 좋습니다.","JPN":"そして……大切な人々がそばにいてくれるここが、好きです。","ENG":"And... I love this place where those dear to me are close by.","TWN":"而且……我喜歡有珍貴的人陪伴在身邊的這個地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_35"},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"좋아하는 걸 지키기 위해 제 한 몸 불사르는 것을 어찌 희생이라 할 수 있겠나요.","JPN":"好きなものを守るために自分の体を張ることを犠牲とは言えません。","ENG":"If I burn myself up to protect the things I love, how could that ever be called sacrifice?","TWN":"為了守護我所愛的東西，獻出我的生命又怎能稱為犧牲呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_36"},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는-","JPN":"私は……","ENG":"I–","TWN":"我-"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_37"},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는, 저를 믿어준 사람들의 곁을 지키고 싶습니다.","JPN":"私は、自分を信じてくれた人々のそばにいたいです。","ENG":"I-I want to protect those who believe in me.","TWN":"我想守護那些相信我的人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_51"},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"만약 별빛이 인도하는 길에 정의가 없다면…….","JPN":"もし星の光が導いてくれる道に正義がないなら……","ENG":"If the path guided by the stars holds no justice...","TWN":"如果星光指引的道路上沒有正義……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_52"},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제가 그 길에 정의를 새기겠습니다.","JPN":"私がその道に正義を刻みましょう。","ENG":"Then I'll carve justice into it myself.","TWN":"我將在那條路上刻下正義。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_53"},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제가, 스러져간 별들의 이야기를 이어 나가겠습니다.","JPN":"私が、消えていった星々の話を続けましょう。","ENG":"I'll carry on the story of the stars that fell.","TWN":"我將繼續講述那些隕落星辰的故事。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_54"},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……얄궂구나.","JPN":"……皮肉なものね。","ENG":"...How strange.","TWN":"……真是奇怪啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_38"},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"더는…… 누군가에게 기대서는 안 된다고 생각했건만.","JPN":"もう……誰かに頼ってはいけないと思っていたのに。","ENG":"I thought I'd never lean on anyone again.","TWN":"我以為自己再也不能依靠任何人了……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_39"},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어리광을 부리는 건 제 쪽이라고 생각합니다.","JPN":"甘えているのは私の方です。","ENG":"If anyone's being selfish, it's me.","TWN":"我覺得撒嬌的是我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_55"},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그럴 듯하게 말하고 있지만, 결국 그레이스 경에게 기대는 셈이니까요.","JPN":"それらしいことを言っていますが、結局グレース卿に頼ることになっていますから。","ENG":"I talk big, but in the end, I'm relying on you, Dame Grace.","TWN":"雖然說得好聽，但最終還是依賴葛瑞絲小姐啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_56"},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"탐욕의 끝은 그대가 바라던 결말과는 다를지도 모릅니다.","JPN":"貪欲の果てはあなたの望んでいた結果とは違うかもしれませんよ。","ENG":"This path you've chosen may not lead where you hoped.","TWN":"貪欲的盡頭可能與你期望的結局不同。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_40"},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그럼에도, 저는 이곳에 있습니다.","JPN":"それでも、私はここにいます。","ENG":"Even so, I remain here.","TWN":"儘管如此，我還是在這裡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_57"},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……그 선택이.","JPN":"……その選択が。","ENG":"...Then can you...","TWN":"……這樣的選擇啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_41"},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제게 있어 후회스럽지 않으리라 맹세해주실 수 있습니까?","JPN":"私にとって後悔するような選択ではないと、誓ってくれますか？","ENG":"Swear that this choice won't end in regret?","TWN":"你能向我保證不會後悔嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_42"},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예.","JPN":"はい。","ENG":"I swear.","TWN":"是的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_58"},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제 모든 것을 걸고서, 반드시.","JPN":"私のすべてをかけて、必ず。","ENG":"With everything I have, I will.","TWN":"我將傾盡所有，務必做到。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_59"},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"아스러진 별이 잠시 어둠을 밝힐 때.","JPN":"粉々になった星が束の間、闇を照らす時。","ENG":"As a fading star lights the dark for just a moment.","TWN":"破碎的星星暫時照亮了黑暗。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"깊은 잠에서 깨어난 이는 별을 바라보았다.","JPN":"深い眠りから目を覚めた者は、星を見つめた。","ENG":"The one who had slept awoke and looked skyward.","TWN":"從沉睡中醒來的人仰望星星。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"잠기지 않은 빛에 소망을 담아.","JPN":"救いの光に願いを込めて。","ENG":"Placing hope in that unyielding light.","TWN":"將希望寄託於未熄滅的光芒。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"곧 펼쳐질 찬란한 하늘을 그 속에 헤아렸다.","JPN":"もうすぐ広がる輝かしい空を、その中から見出した。","ENG":"And dreaming of a radiant sky yet to come.","TWN":"即將展開的燦爛天空在其中被揣測。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……수 세기가 지나 사랑하던 이의 목소리조차 희미해진 기억이 못내 원망스러워도.","JPN":"……数世紀が過ぎて、愛する人の声すらもおぼろげになってしまった記憶が恨めしくても。","ENG":"...Even if centuries pass and I forget the voice I loved.","TWN":"……即使經過了幾個世紀，連愛人的聲音都變得模糊不清的記憶仍然令人怨恨。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_43"},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그 시절의 행복이, 작별이란 단어에 안식을 더해 주더군요.","JPN":"あの頃の幸せが、別れという言葉に安息を添えてくれました。","ENG":"The joy we shared... gives peace to our parting.","TWN":"那時的幸福，為告別這個詞增添了安息。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_44"},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"에스테로사 경. 못다한 <color=#ffd34c>질문</color>에 답을 하면, 우리에게 후회란 없습니다.","JPN":"エステロサ卿。まだ答えられなった<color=#ffd34c>質問</color>にお答えしますと、私たちに後悔などありません。","ENG":"Esterosa. If I answer that unfinished <color=#ffd34c>question</color>, there will be no regrets.","TWN":"艾斯特洛索。回答未盡的<color=#ffd34c>問題</color>，我們就不會有遺憾。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_45"},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오랜 기다림 끝에 비로소…… 소임을 다하였으니.","JPN":"待ちに待ったこの日、やっと……役目を果たせた。","ENG":"After so long... I've finally fulfilled my role.","TWN":"經過漫長的等待，終於……完成了使命。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_46"},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"기사의 명예란 맹세에 어긋나지 않는 길을 걸으면 자연스레 빛나는 법.","JPN":"騎士の名誉とは、誓った道をひたすら歩けば自ずと輝くもの。","ENG":"A knight's honor shines brightest when they walk a path true to their vow.","TWN":"所謂騎士的名譽，只要堅守誓言，有一天自然會發光。"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_47"},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그대들의 주인은 오직 고통받는 이들일지니, 운명에 희생된 비통한 목소리를 대신하여 이 영광된 의식을 거행한다.","JPN":"そなたたちの主は苦しみに満ちた者たちのみ。運命の犠牲となった悲痛な声に代わり、この栄光なる儀式を執り行おう。","ENG":"You serve no one but the afflicted. I hereby officiate this honorable ceremony on behalf of the mournful voices silenced by fate.","TWN":"你們的主人是那些受苦的人，我在此代替那些哀痛的聲音，舉行這榮耀的儀式。"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_48"},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"성좌의 광명을 따르며 만인을 지키기로 맹세할 자, 누구인가?","JPN":"星座の光明に従い、万人を守ると誓う者は誰だ。","ENG":"Who pledges today to follow the radiance of the constellations and protect humanity?","TWN":"跟從星座之光，宣示要守護萬民的人，是誰？"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_49"},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……에스테로사. 드높은 별의 인도로 이 자리에 섰습니다.","JPN":"……エステロサ、誇り高き星の導きよりこの場に辿り着きました。","ENG":"...I, Esterosa, stand here under the guidance of the stars.","TWN":"我 艾斯特洛索，跟從正義之星的引導站立在這位置上。"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_60"},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그대는 길을 잃어 어둠 속을 헤매는 이들에게 무엇을 맹세하겠는가?","JPN":"そなたは道に迷い、闇の中で彷徨う者たちに何を誓うか。","ENG":"And what do you vow, to those who wander lost in the dark?","TWN":"你會對那些在黑暗中迷失方向的人們許下什麼誓言？"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_50"},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"적막한 밤의 평화. 별처럼 빛나는 희망.","JPN":"寂寞たる夜の平和。星のごとく光る希望。","ENG":"The peace of a quiet night. Hope that shines like the stars.","TWN":"我宣示，寂靜的夜晚中有和平，希望如星閃耀，以及黎明必將到來。"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_61"},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여러분들이 보지 못한, 내일의 새벽을 맞이하리라는 믿음을 맹세합니다.","JPN":"皆さんが見ることができなかった、次の夜明けが訪れると信じる心を誓います。","ENG":"And the promise that even if unseen, we will greet the dawn together.","TWN":"諸位，我在此向你等立下誓言，明天的黎明終將會到來。"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_62"},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그대들의 기원인 별의 인도자이자, 스러져간 별들을 대신하여 이 자리에서 선언한다.","JPN":"そなたたちの起源である星の導き手であり、消えていった星々の代わりにこの場で宣言する。","ENG":"As the Star Guide and voice of the fallen, I proclaim this now.","TWN":"我在此宣告，作為你們祈願的星之引導者，代替那些隕落的星星。"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_51"},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그대가…….","JPN":"そなたが……","ENG":"You are...","TWN":"你是……"},"stage":{"bg":"PRIDE_01","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_52"},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"우리가 남긴 최후의 별빛임을.","JPN":"我々が残した最後の星の光であることを。","ENG":"The last starlight we leave behind.","TWN":"我們留下的最後星光。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_53"},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_COUNT_NULL_NULL","text":{"KOREA":"아아… 그레이스… 경…….","JPN":"ああ……グレース……卿……","ENG":"Aah... Dame... Grace...","TWN":"啊啊…葛瑞絲…小姐……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_COUNT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_COUNT_NULL_NULL","text":{"KOREA":"이제… 편…… 히…….","JPN":"もう……安らか……に……","ENG":"Now... may you...","TWN":"現在……安……心……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_COUNT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_COUNT_NULL_NULL","text":{"KOREA":"쉬시길…….","JPN":"お眠りください……","ENG":"Rest in peace...","TWN":"請休息……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_COUNT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"지팡이에 담긴 클리파 허수 에너지가… 소실된다고?","JPN":"杖に宿ったクリファ虚数エネルギーが……消失した？","ENG":"The Qlipha Imaginary Energy in the Staff is... disappearing?!","TWN":"杖中的逆卡巴拉虛數能量……要消失了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"마, 말도 안 돼. 갑자기 어째서…!!","JPN":"そ、そんな。いきなりなんで……！！","ENG":"W-what?! That's impossible! How...?!!","TWN":"太、太不像話了。突然為什麼…！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"저 빛은……. 설마?","JPN":"あの光は……まさか？","ENG":"That light... Could it be?","TWN":"那道光……難道？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래. 누구 동생 아니랄까 봐 화려하게도 저질렀어.","JPN":"そうね。あの人の妹らしく、派手にやってるわね。","ENG":"Of course. Flashy to the end, just like her brother.","TWN":"是啊，怕人家不知道你是誰的妹妹嗎？幹得真漂亮。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"질투 날 지경이야, 정말.","JPN":"羨ましいくらいだわ。","ENG":"Honestly, I'm kind of jealous.","TWN":"我都快嫉妒死了，真的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"와아~. 유성우가 쏟아지고 있어요.","JPN":"わあ～流れ星がいっぱい流れてます。","ENG":"Wow...! It's a meteor shower!","TWN":"哇～流星雨正在傾瀉而下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"마치… 하늘에 계신 별님이 웃고 계신 거 같아요.","JPN":"まるで……空のお星さまが笑ってるみたい。","ENG":"It's like... the stars in the sky are smiling at us.","TWN":"彷彿……天上的星星在微笑呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……예. 제게도 그렇게 보이는군요..","JPN":"……はい。私にもそう見えます。","ENG":"Yes. That's how it looks to me too.","TWN":"是的。我也這麼覺得。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사들이여! 고개를 들어 하늘을 봐라!","JPN":"騎士たちよ！　頭を上げて空を見ろ！","ENG":"Knights, raise your heads and look to the sky!","TWN":"騎士們！抬起頭來看天空！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하늘에 떠오른 성좌가, 스러져간 별들의 기원이 우리를 지켜보고 있다!","JPN":"空に浮かび上がった星座が、消えていった星たちの起源が我々を見守っている！","ENG":"The constellations shine above us, and the will of the fallen stars watches over us!","TWN":"升起在天空的星座，逝去的星辰的祈願正在守護著我們！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그들이 건넨 희망이, 결코 닿을 리 없던 별들이 또한 이곳에서 빛나고 있음을.","JPN":"彼らが託した希望が、決して届くはずのなかった星たちが。ここで光り輝いているのだと。","ENG":"Their hope, their light, shines even now in this place.","TWN":"他們傳遞的希望，以及那些本不可能觸及的星星，也在這裡閃耀著。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그대들의 정의로 입증하라!!","JPN":"そなたらの正義で証明するのだ！！","ENG":"Prove it with your justice!!","TWN":"用你們的正義來證明吧！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_CHARLOTTE_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하. 천한 것들이 요상하게도 소란이군.","JPN":"は。下賤なものどもが騒がしいな。","ENG":"Hah. How the rabble squawks and squeals.","TWN":"卑賤的東西居然如此喧鬧。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"자신들이 정의인 양 믿는 별들은 이미 쇠락한 지 오래인데, 애석한 것들 같으니.","JPN":"自分たちが正義だと信じている星たちはすでに衰え落ちたというのに、悲しいことだ。","ENG":"Those who claim to be justice don't even realize their stars have long since faded.","TWN":"那些自以為是正義的星辰早已衰落，真是可悲的傢伙。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"자아. 이로써 계승식의 모든 절차는 마무리되었다.","JPN":"さあ。これにて継承式のすべての手順は終わった。","ENG":"Alas, all the rites of succession are complete.","TWN":"好了。至此，繼承儀式的所有程序都已完成。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"마침내 내 오랜 숙원이…….","JPN":"ついに我が宿願が……","ENG":"My long-cherished wish is finally–","TWN":"終於我的夙願……"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"뭐냐.","JPN":"なに？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"고유무장의 별빛이… 사라졌다고?","JPN":"固有武装の星の光が……消えただと？","ENG":"The starlight in the Unique Gear is... gone?!","TWN":"專屬武裝的星光……消失了？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"빌어먹을. 이게 대체 어떻게 된 거냐!","JPN":"くそ。これはいったいどういうことだ！","ENG":"Damn it. How can this happen?!","TWN":"該死，這到底是怎麼回事！"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"분명 의식에 필요한 모든 조건은 갖춰졌을 텐데……!","JPN":"儀式に必要なすべての条件は、確かに揃ったはずだ……！","ENG":"All the conditions for the ritual should've been met...!","TWN":"明明已經具備了意識所需的所有條件……！"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"아니. 네놈은 가장 중요한 걸 갖추지 못했다.","JPN":"いや。貴様は一番重要なものを持ち合わせていない。","ENG":"No. You failed to meet the most important one.","TWN":"不，你缺少了最重要的東西。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"기사의 길을 벗어난 네게 이 맹세를 짊어질 자격은 없어.","JPN":"騎士の道から外れた貴様に、この誓いを背負う資格などない。","ENG":"You strayed from the path of the knight. You've no right to carry that vow.","TWN":"你沒有資格承擔這份誓言，因為你已經偏離了騎士之路。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이, 이게…… 이건…… 이럴 리가……","JPN":"こ、これが……これは……こんなはずは……","ENG":"Th-this can't be...","TWN":"什、什麼……不……不可能……"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈이, 대체 어떻게…?","JPN":"貴様が、いったいどうやって……？","ENG":"How did you...?!","TWN":"你這傢伙，到底是怎麼……？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"오래 기다렸다, 카란티시르.","JPN":"待っていた、カランティシル。","ENG":"I've been waiting a long time, Carantisir.","TWN":"久等了，卡蘭堤西爾。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"이제, 길었던 여정에 종지부를 찍자.","JPN":"長かった旅路に終わりを告げよう。","ENG":"Now, let's bring this long journey to its end.","TWN":"現在，讓我們為漫長的旅程畫上句號吧。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};